// --- helpers ---

func customerBadgeLabel(name, code string) string {
	if name == "" {
		return ""
	}
	if code != "" {
		return code + " · " + name
	}
	return name
}

func accountActiveClass(id, selected string) string {
	if id == selected {
		return "text-amber-400 bg-neutral-800/60"
	}
	return "text-neutral-300"
}

func folderActiveClass(name, active string) string {
	if name == active {
		return "text-amber-400 bg-neutral-800/60"
	}
	return "text-neutral-400"
}

func firstParticipant(s string) string {
	if s == "" {
		return ""
	}
	parts := splitComma(s)
	if len(parts) == 0 {
		return s
	}
	return parts[0]
}

func splitComma(s string) []string {
	if s == "" {
		return nil
	}
	var out []string
	start := 0
	for i, c := range s {
		if c == ',' {
			out = append(out, s[start:i])
			start = i + 1
		}
	}
	out = append(out, s[start:])
	return out
}

func nonSystemTags(tags []emailqueries.TagReadModel) []emailqueries.TagReadModel {
	var out []emailqueries.TagReadModel
	for _, t := range tags {
		if !t.System {
			out = append(out, t)
		}
	}
	return out
}

func isStarred(tags []emailqueries.TagReadModel) bool {
	for _, t := range tags {
		if t.Name == "starred" {
			return true
		}
	}
	return false
}

